// Parse et valide le body
var body = $input.first().json.body || $input.first().json;

var tenantId = String(body.tenantId || '').replace(/[^a-f0-9-]/gi, '');
var leadId = String(body.leadId || '').replace(/[^a-f0-9-]/gi, '');
var channel = ['telephone', 'sms', 'web'].includes(body.channel) ? body.channel : 'telephone';
var status = ['en_cours', 'complete', 'abandonne'].includes(body.status) ? body.status : 'en_cours';

// Questions: array de {question, answer, order}
var questions = [];
try {
  var raw = body.questions || [];
  if (typeof raw === 'string') raw = JSON.parse(raw);
  for (var i = 0; i < raw.length; i++) {
    questions.push({
      question: String(raw[i].question || '').substring(0, 500),
      answer: raw[i].answer ? String(raw[i].answer).substring(0, 1000) : null,
      order: raw[i].order || (i + 1)
    });
  }
} catch(e) {}

var completedAt = status === 'complete' ? new Date().toISOString() : null;

return [{ json: { tenantId, leadId, channel, status, questions, completedAt } }];

