  var completedAt = d.completedAt ? "'" + d.completedAt + "'" : 'NULL';
  return "INSERT INTO questionnaires (id, tenant_id, lead_id, questions, status, channel, completed_at, created_at, updated_at) "
    + "VALUES ('" + id + "', '" + d.tenantId + "', '" + d.leadId + "', '" + questionsJson + "'::jsonb, '" + d.status + "', '" + d.channel + "', " + completedAt + ", NOW(), NOW()) "
    + "RETURNING id, tenant_id, lead_id, status, channel, created_at";
})() }}

